import React, { useEffect, useState } from 'react';
import { getCurrentUser, listIssues, listNotifs } from '../../services/mockApi';
import { useNavigate } from 'react-router-dom';

export default function ForYou() {
  const navigate = useNavigate();
  const [user, setUser] = useState(getCurrentUser());
  const [issues, setIssues] = useState([]);
  const [notifications, setNotifications] = useState([]);
  const [showTodayOnly, setShowTodayOnly] = useState(false);

  useEffect(() => {
    listIssues().then((res) => {
      if (Array.isArray(res)) {
        setIssues(res);
      } else if (res?.data && Array.isArray(res.data)) {
        setIssues(res.data);
      } else {
        setIssues([]);
      }
    });

    listNotifs().then((res) => {
      if (Array.isArray(res)) {
        setNotifications(res);
      } else if (res?.data && Array.isArray(res.data)) {
        setNotifications(res.data);
      } else {
        setNotifications([]);
      }
    });
  }, []);

  const mine = Array.isArray(issues)
    ? issues.filter((i) => i.assignee === user?.id)
    : [];

  const today = new Date().toISOString().slice(0, 10);
  const thisWeek = new Date();
  thisWeek.setDate(thisWeek.getDate() + 7);
  const weekEnd = thisWeek.toISOString().slice(0, 10);

  const filteredIssues = mine.filter((i) => {
    if (!i.dueDate) return false;
    if (showTodayOnly) return i.dueDate === today;
    return i.dueDate >= today && i.dueDate <= weekEnd;
  });

  return (
    <div style={{
      display: 'flex',
      height: '100vh',
      fontFamily: 'system-ui, -apple-system, sans-serif',
      backgroundColor: '#fff'
    }}>
      {/* Sidebar */}
      <div style={{
        width: '250px',
        backgroundColor: '#f8f9fa',
        borderRight: '1px solid #e1e5e9',
        padding: '1.5rem 1rem'
      }}>
        <div style={{
          fontSize: '0.8rem',
          color: '#666',
          marginBottom: '2rem',
          paddingLeft: '0.5rem'
        }}>
          ADMIN
        </div>

        <div style={{
          fontSize: '0.75rem',
          color: '#999',
          marginBottom: '0.5rem',
          paddingLeft: '0.5rem'
        }}>
          MacBook Air - 1
        </div>

        <div style={{
          height: '1px',
          backgroundColor: '#e1e5e9',
          margin: '1.5rem 0'
        }}></div>

        <div style={{
          fontSize: '0.8rem',
          color: '#666',
          marginBottom: '1rem',
          paddingLeft: '0.5rem'
        }}>
          FLOW TRACK
        </div>

        <div style={{
          marginBottom: '2rem',
          paddingLeft: '0.5rem'
        }}>
          <div style={{
            padding: '0.5rem 0',
            color: '#1976d2',
            fontWeight: '500',
            fontSize: '0.9rem'
          }}>For You</div>
          <div style={{
            padding: '0.5rem 0',
            color: '#666',
            fontSize: '0.9rem'
          }}>Projects</div>
          <div style={{
            padding: '0.5rem 0',
            color: '#666',
            fontSize: '0.9rem'
          }}>Boards</div>
          <div style={{
            padding: '0.5rem 0',
            color: '#666',
            fontSize: '0.9rem'
          }}>Assets</div>
          <div style={{
            padding: '0.5rem 0',
            color: '#666',
            fontSize: '0.9rem'
          }}>Timeline</div>
          <div style={{
            padding: '0.5rem 0',
            color: '#666',
            fontSize: '0.9rem'
          }}>Users</div>
        </div>

        <div style={{
          height: '1px',
          backgroundColor: '#e1e5e9',
          margin: '1.5rem 0'
        }}></div>

        <div style={{
          fontSize: '0.8rem',
          color: '#666',
          marginBottom: '1rem',
          paddingLeft: '0.5rem'
        }}>
          FLOW TRACK
        </div>

        <div style={{
          paddingLeft: '0.5rem',
          marginBottom: '2rem'
        }}>
          <div style={{
            fontSize: '0.9rem',
            color: '#666',
            marginBottom: '0.25rem'
          }}>Welcome User,</div>
          <div style={{
            fontSize: '0.8rem',
            color: '#999'
          }}>Here's what's happening this week</div>
        </div>

        <div style={{
          position: 'absolute',
          bottom: '2rem',
          fontSize: '0.8rem',
          color: '#666'
        }}>
          <div>User@gmail.com</div>
          <div style={{ color: '#1976d2', marginTop: '0.25rem' }}>Sign out</div>
        </div>
      </div>

      {/* Main Content */}
      <div style={{
        flex: 1,
        padding: '2rem',
        backgroundColor: '#fff'
      }}>
        <div style={{
          display: 'grid',
          gridTemplateColumns: '1fr 1fr',
          gap: '2rem',
          maxWidth: '900px'
        }}>
          {/* Your Boards */}
          <div style={{
            gridColumn: '1 / -1'
          }}>
            <div style={{
              display: 'flex',
              justifyContent: 'space-between',
              alignItems: 'center',
              marginBottom: '1.5rem'
            }}>
              <h2 style={{
                fontSize: '1.1rem',
                fontWeight: '600',
                color: '#1a1a1a',
                margin: 0
              }}>
                Your Boards
              </h2>
              <label style={{
                fontSize: '0.8rem',
                color: '#666',
                display: 'flex',
                alignItems: 'center'
              }}>
                <input
                  type="checkbox"
                  checked={showTodayOnly}
                  onChange={() => setShowTodayOnly(!showTodayOnly)}
                  style={{ marginRight: '0.5rem' }}
                />
                Show only today's tasks
              </label>
            </div>

            <div style={{
              fontSize: '0.8rem',
              color: '#999',
              marginBottom: '1rem'
            }}>
              Recently Viewed
            </div>

            <div style={{
              border: '1px solid #e1e5e9',
              borderRadius: '8px',
              overflow: 'hidden'
            }}>
              {filteredIssues.length > 0 ? (
                filteredIssues.map((i) => (
                  <div key={i.id} style={{
                    padding: '1rem',
                    borderBottom: '1px solid #e1e5e9',
                    backgroundColor: '#fff'
                  }}>
                    <div style={{
                      fontSize: '0.9rem',
                      fontWeight: '500',
                      marginBottom: '0.5rem'
                    }}>
                      {i.title}
                    </div>
                    <div style={{
                      display: 'flex',
                      alignItems: 'center',
                      fontSize: '0.75rem',
                      color: '#666'
                    }}>
                      <span style={{
                        padding: '0.2rem 0.5rem',
                        borderRadius: '4px',
                        backgroundColor: i.status === 'Open' ? '#e8f5e8' : '#ffe8e8',
                        color: i.status === 'Open' ? '#2e7d32' : '#d32f2f',
                        marginRight: '0.75rem'
                      }}>
                        {i.status}
                      </span>
                      Due: {i.dueDate}
                    </div>
                  </div>
                ))
              ) : (
                <div style={{
                  padding: '2rem',
                  textAlign: 'center',
                  color: '#999',
                  fontSize: '0.9rem'
                }}>
                  No tasks found
                </div>
              )}
            </div>
          </div>

          {/* Quick Actions */}
          <div>
            <h2 style={{
              fontSize: '1.1rem',
              fontWeight: '600',
              color: '#1a1a1a',
              margin: '0 0 1rem 0'
            }}>
              Quick Actions
            </h2>
            <div style={{
              border: '1px solid #e1e5e9',
              borderRadius: '8px',
              padding: '1rem',
              backgroundColor: '#fff'
            }}>
              <button style={{
                backgroundColor: '#1976d2',
                color: 'white',
                padding: '0.75rem 1rem',
                borderRadius: '6px',
                border: 'none',
                width: '100%',
                fontSize: '0.9rem',
                fontWeight: '500',
                cursor: 'pointer'
              }} onClick={() => navigate('/projects')}>
                Create Project
              </button>
            </div>
          </div>

          {/* Empty column for balance */}
          <div></div>
        </div>
      </div>
    </div>
  );
}
